"use strict";(self.webpackChunkdeveloper_playcanvas_com=self.webpackChunkdeveloper_playcanvas_com||[]).push([["10194"],{5892(t){t.exports=JSON.parse('{"tag":{"label":"tutorial","permalink":"/tags/tutorial","allTagsPath":"/tags","count":96,"items":[{"id":"tutorials/360-lookaround-camera","title":"360 lookaround camera","description":"Use mouse and touch to rotate the camera and look around a scene for a panoramic or first-person style viewer.","permalink":"/tutorials/360-lookaround-camera"},{"id":"tutorials/gaussian-splat-annotations","title":"3D Gaussian Splat Annotations","description":"Build a Gaussian splat product viewer with clickable hotspots and UI annotations over the captured scene.","permalink":"/tutorials/gaussian-splat-annotations"},{"id":"tutorials/gaussian-splat-physics-and-relighting","title":"3D Gaussian Splat Physics and Relighting","description":"Combine SOG splats with shadows, dynamic relighting, and physics for walkable real-world scanned spaces.","permalink":"/tutorials/gaussian-splat-physics-and-relighting"},{"id":"tutorials/gaussian-splat-statues","title":"3D Gaussian Splat Statues","description":"Present a gallery of Gaussian splat statues with custom shaders and post effects between exhibit transitions.","permalink":"/tutorials/gaussian-splat-statues"},{"id":"tutorials/gaussian-splat-streaming-lod","title":"3D Gaussian Splat Streamed SOG","description":"Stream huge Gaussian splat scenes with Streamed SOG so large environments load progressively.","permalink":"/tutorials/gaussian-splat-streaming-lod"},{"id":"tutorials/animate-entities-with-curves","title":"Animate entities with curves","description":"Drive entity motion with animation curves for simple scripted movement without building a full Anim State Graph.","permalink":"/tutorials/animate-entities-with-curves"},{"id":"tutorials/animation-without-state-graph","title":"Animation without State Graph","description":"Play and control animation clips from scripts without an Anim State Graph for straightforward playback and tests.","permalink":"/tutorials/animation-without-state-graph"},{"id":"tutorials/advance-loading-screen","title":"Base64 Loading Screen Images","description":"Customize the loading screen with embedded Base64 images so branding and splash art show while the app initializes.","permalink":"/tutorials/advance-loading-screen"},{"id":"tutorials/basic-touch-input","title":"Basic touch input","description":"Handle touch events to drag and move on-screen objects for a minimal mobile-first interaction sample.","permalink":"/tutorials/basic-touch-input"},{"id":"tutorials/billboards","title":"Billboards","description":"Keep planes facing the camera for trees, flares, and sprites that always show their front toward the viewer.","permalink":"/tutorials/billboards"},{"id":"tutorials/camera-following-a-path","title":"Camera following a path","description":"Animate a camera along a spline path through waypoints for flythroughs and guided cinematic motion.","permalink":"/tutorials/camera-following-a-path"},{"id":"tutorials/camera-model-masking","title":"Camera model masking","description":"Use camera and light mask groups so specific lights and views only affect chosen models in layered scenes.","permalink":"/tutorials/camera-model-masking"},{"id":"tutorials/capturing-a-screenshot","title":"Capturing a screenshot","description":"Render from a camera to a texture and export pixels as a PNG for captures and sharing from your app.","permalink":"/tutorials/capturing-a-screenshot"},{"id":"tutorials/changing-textures-at-runtime","title":"Changing textures at runtime","description":"Swap a material texture map from script to retexture models on the fly without duplicating mesh assets.","permalink":"/tutorials/changing-textures-at-runtime"},{"id":"tutorials/create-qr-code-at-runtime","title":"Create QR Code at runtime","description":"Generate QR codes in the browser at runtime with a small library and show them in UI or on textures.","permalink":"/tutorials/create-qr-code-at-runtime"},{"id":"tutorials/creating-rigid-bodies-in-code","title":"Creating Rigid Bodies in Code","description":"Spawn entities with collision and rigidbody components entirely from scripts for procedural physics objects.","permalink":"/tutorials/creating-rigid-bodies-in-code"},{"id":"tutorials/detecting-a-double-click","title":"Detecting a double click","description":"Detect double-clicks with timing logic and use them to move the camera or trigger actions on desktop browsers.","permalink":"/tutorials/detecting-a-double-click"},{"id":"tutorials/detecting-a-double-tap","title":"Detecting a double tap","description":"Recognize double-tap gestures on touchscreens separately from single taps for mobile-friendly interactions.","permalink":"/tutorials/detecting-a-double-tap"},{"id":"tutorials/detecting-a-long-press","title":"Detecting a long press","description":"Measure press duration on touch or mouse to fire actions after the user holds on an element long enough.","permalink":"/tutorials/detecting-a-long-press"},{"id":"tutorials/dynamic-ui-scroll-view","title":"Dynamic UI Scroll View","description":"Add and remove scroll view children at runtime to build lists and feeds with PlayCanvas screen-space UI.","permalink":"/tutorials/dynamic-ui-scroll-view"},{"id":"tutorials/entity-picking-using-physics","title":"Entity picking using physics","description":"Cast physics raycasts from the pointer to hit colliders and select entities under the cursor in 3D.","permalink":"/tutorials/entity-picking-using-physics"},{"id":"tutorials/entity-picking-without-physics","title":"Entity picking without physics","description":"Pick meshes using math ray tests instead of the physics engine to avoid extra runtime weight in published builds.","permalink":"/tutorials/entity-picking-without-physics"},{"id":"tutorials/explosion-particle-effect","title":"Explosion Particle Effect","description":"Layer particle emitters with camera shake to sell an explosion impact and debris burst in real time.","permalink":"/tutorials/explosion-particle-effect"},{"id":"tutorials/fading-objects-in-and-out","title":"Fading objects in and out","description":"Animate material opacity so individual models fade in and out without duplicating geometry or materials.","permalink":"/tutorials/fading-objects-in-and-out"},{"id":"tutorials/first-person-shooter-starter-kit","title":"First Person Shooter Starter Kit","description":"Extend first-person controls with jumping and navigation as a starter for FPS-style movement prototypes.","permalink":"/tutorials/first-person-shooter-starter-kit"},{"id":"tutorials/flaming-fireball","title":"Flaming fireball","description":"Drive a particle fireball that follows the pointer for a simple magical projectile and trail effect.","permalink":"/tutorials/flaming-fireball"},{"id":"tutorials/flappy-bird","title":"Flappy Bird","description":"Recreate Flappy Bird-style tap flight with pipes and scoring as a compact PlayCanvas gameplay sample.","permalink":"/tutorials/flappy-bird"},{"id":"tutorials/frames-per-sec-fps-counter","title":"Frames Per Sec (FPS) counter","description":"Add a lightweight FPS overlay script to monitor frame rate during development and performance tuning.","permalink":"/tutorials/frames-per-sec-fps-counter"},{"id":"tutorials/htmlcss---live-updates","title":"HTML/CSS - Live Updates","description":"Edit HTML and CSS assets with live reload so HUD changes appear instantly while the scene keeps running.","permalink":"/tutorials/htmlcss---live-updates"},{"id":"tutorials/htmlcss-ui","title":"HTML/CSS UI","description":"Build layered HUDs and menus with standard HTML and CSS composited over the WebGL canvas.","permalink":"/tutorials/htmlcss-ui"},{"id":"tutorials/information-hotspots","title":"Information hotspots","description":"Place clickable hotspots in the 3D view that open info panels using raycasts and screen overlays.","permalink":"/tutorials/information-hotspots"},{"id":"tutorials/load-assets-with-a-progress-bar","title":"Load assets with a progress bar","description":"Load multiple runtime assets while updating a UI progress bar so users see download and parse progress during loads.","permalink":"/tutorials/load-assets-with-a-progress-bar"},{"id":"tutorials/load-multiple-assets-at-runtime","title":"Load multiple assets at runtime","description":"Load several assets after startup using PlayCanvas asset APIs instead of preloading every file before the scene begins.","permalink":"/tutorials/load-multiple-assets-at-runtime"},{"id":"tutorials/loading-an-asset-at-runtime","title":"Loading an asset at runtime","description":"Load a single asset on demand so unused resources stay off the initial preload list until your script requests them.","permalink":"/tutorials/loading-an-asset-at-runtime"},{"id":"tutorials/loading-circle-ui","title":"Loading Circle UI","description":"Implement a radial loading spinner UI with materials and animation for clear feedback while content streams in.","permalink":"/tutorials/loading-circle-ui"},{"id":"tutorials/loading-draco-compressed-glbs","title":"Loading Draco Compressed GLBs","description":"Load Draco-compressed GLB models in PlayCanvas with the right pipeline so meshes stay small without breaking rendering.","permalink":"/tutorials/loading-draco-compressed-glbs"},{"id":"tutorials/loading-gltf-glbs","title":"Loading glTF GLBs","description":"Load glTF GLB files as binary assets at runtime and add the resulting model instance to your PlayCanvas scene hierarchy.","permalink":"/tutorials/loading-gltf-glbs"},{"id":"tutorials/locking-the-mouse","title":"Locking the mouse","description":"Request pointer lock on click to capture the mouse for first-person look, hiding the cursor while movement drives the camera.","permalink":"/tutorials/locking-the-mouse"},{"id":"tutorials/mobile-ui-safe-areas","title":"Mobile UI Safe Areas","description":"Lay out screen UI inside notched and rounded device safe areas so controls stay clear of system bars and hardware cutouts.","permalink":"/tutorials/mobile-ui-safe-areas"},{"id":"tutorials/multiple-camera-layers","title":"Multiple Camera Layers","description":"Combine multiple cameras and render layers to mix screen-space UI with world-space elements in one PlayCanvas scene.","permalink":"/tutorials/multiple-camera-layers"},{"id":"tutorials/multiple-viewport-rendering","title":"Multiple Viewport Rendering","description":"Split the canvas into separate camera viewports by adjusting each camera rectangle for picture-in-picture or split-screen views.","permalink":"/tutorials/multiple-viewport-rendering"},{"id":"tutorials/multitouch-input","title":"Multitouch input","description":"Track every active touch point and visualize multitouch gestures by drawing lines between fingers on the screen.","permalink":"/tutorials/multitouch-input"},{"id":"tutorials/orange-room","title":"Orange Room","description":"Explore an interior archviz sample with dynamic reflections and baked HDR lightmaps for realistic lighting and materials.","permalink":"/tutorials/orange-room"},{"id":"tutorials/orbit-camera","title":"Orbit camera","description":"Implement an orbit camera with mouse and touch, including scroll-wheel zoom and pinch-to-zoom around a focal entity.","permalink":"/tutorials/orbit-camera"},{"id":"tutorials/pan-camera-to-target","title":"Pan Camera to Target","description":"Smoothly move and aim the camera toward a world-space target so clicks or events frame important locations in the scene.","permalink":"/tutorials/pan-camera-to-target"},{"id":"tutorials/pauseplay-application","title":"Pause/Play application","description":"Pause and resume gameplay by toggling Application timeScale so physics, animations, and time-based logic freeze together.","permalink":"/tutorials/pauseplay-application"},{"id":"tutorials/physics-raycasting-by-tag","title":"Physics raycasting by tag","description":"Filter physics raycast hits by entity tags so picking ignores the wrong colliders and only selects intended objects.","permalink":"/tutorials/physics-raycasting-by-tag"},{"id":"tutorials/physics-with-ccd","title":"Physics with CCD","description":"Enable continuous collision detection on rigidbodies so fast projectiles do not tunnel through thin colliders between steps.","permalink":"/tutorials/physics-with-ccd"},{"id":"tutorials/place-an-entity-with-physics","title":"Place an entity with physics","description":"Spawn physics-enabled props at clicked world positions using raycasts against the ground so new bodies collide correctly.","permalink":"/tutorials/place-an-entity-with-physics"},{"id":"tutorials/place-entity-without-physics","title":"Place entity without physics","description":"Instantiate decorative entities at clicked ground positions using math and raycasts without adding rigidbody simulation.","permalink":"/tutorials/place-entity-without-physics"},{"id":"tutorials/planar-mirror-reflection","title":"Planar Mirror Reflection","description":"Render planar reflections for mirrors and water by projecting the scene onto a plane with a reflective shader pass.","permalink":"/tutorials/planar-mirror-reflection"},{"id":"tutorials/planet-earth","title":"Planet Earth","description":"Shade a globe with Earth textures, materials, and shaders to present a stylized planetary body in real time.","permalink":"/tutorials/planet-earth"},{"id":"tutorials/point-and-click-movement","title":"Point and click movement","description":"Move a character or object toward clicked ground positions using screen-to-world raycasts for simple navigation.","permalink":"/tutorials/point-and-click-movement"},{"id":"tutorials/procedural-gradient-texture","title":"Procedural Gradient Texture","description":"Generate a gradient texture in code and apply it to materials instead of importing a bitmap for smooth color ramps.","permalink":"/tutorials/procedural-gradient-texture"},{"id":"tutorials/rainbow-trail-with-mesh-api","title":"Rainbow Trail with Mesh API","description":"Build a rainbow ribbon trail by updating mesh vertices and colors with the Mesh API for dynamic GPU-driven geometry.","permalink":"/tutorials/rainbow-trail-with-mesh-api"},{"id":"tutorials/raycast-with-camera-viewports","title":"Raycast with Camera Viewports","description":"Convert pointer coordinates into per-camera rays when using split viewports so picking hits the correct 3D region in each pane.","permalink":"/tutorials/raycast-with-camera-viewports"},{"id":"tutorials/render-3d-world-to-ui","title":"Render 3D World to UI","description":"Render a 3D preview with a dedicated camera into UI elements such as inventory icons or character selection panels.","permalink":"/tutorials/render-3d-world-to-ui"},{"id":"tutorials/resolution-scaling","title":"Resolution Scaling","description":"Scale internal 3D resolution for performance while keeping crisp screen-space UI by separating world and overlay render paths.","permalink":"/tutorials/resolution-scaling"},{"id":"tutorials/right-to-left-language-support","title":"Right to left language support","description":"Adapt Element component text and layout scripts for right-to-left languages such as Arabic with correct alignment flow.","permalink":"/tutorials/right-to-left-language-support"},{"id":"tutorials/rotating-objects-with-mouse","title":"Rotating Objects with Mouse","description":"Orbit or spin an object by mapping mouse drag deltas in screen space to rotation quaternions or euler angles each frame.","permalink":"/tutorials/rotating-objects-with-mouse"},{"id":"tutorials/shockwave","title":"Shockwave","description":"Add a radial shockwave distortion to the framebuffer with a post-effect shader for impacts and cinematic camera pulses.","permalink":"/tutorials/shockwave"},{"id":"tutorials/simple-shape-raycasting","title":"Simple shape raycasting","description":"Cast a physics ray from the camera through the pointer to detect which entity or shape sits under the cursor.","permalink":"/tutorials/simple-shape-raycasting"},{"id":"tutorials/simple-water-surface","title":"Simple water surface","description":"Approximate a stylized water plane with scrolling normals and fresnel-tinted materials for simple reflective surfaces.","permalink":"/tutorials/simple-water-surface"},{"id":"tutorials/smooth-camera-movement","title":"Smooth camera movement","description":"Ease the camera between positions and orientations each frame using vector lerp and quaternion slerp for cinematic motion.","permalink":"/tutorials/smooth-camera-movement"},{"id":"tutorials/sound-volume-control-using-curve","title":"Sound volume control using curve","description":"Drive a sound slot volume from sampled curve data so loudness follows authored ramps instead of linear code tweaks.","permalink":"/tutorials/sound-volume-control-using-curve"},{"id":"tutorials/space-rocks","title":"Space Rocks!","description":"Fork an Asteroids-style shooter template with mouse aiming, shooting, and waves of rocks to learn arcade game flow.","permalink":"/tutorials/space-rocks"},{"id":"tutorials/static-batching","title":"Static Batching","description":"Merge static meshes into fewer draw calls with batching to cut CPU overhead while keeping non-moving geometry efficient.","permalink":"/tutorials/static-batching"},{"id":"tutorials/stencil-buffer---3d-magic-card","title":"Stencil Buffer - 3D Magic Card","description":"Use stencil tests to mask a playing-card shape and reveal a separate 3D scene through the window like a magic portal.","permalink":"/tutorials/stencil-buffer---3d-magic-card"},{"id":"tutorials/switching-materials-at-runtime","title":"Switching materials at runtime","description":"Swap material assets on render components in code to change colors, shaders, or skins without duplicating mesh entities.","permalink":"/tutorials/switching-materials-at-runtime"},{"id":"tutorials/third-person-controller","title":"Third Person Controller","description":"Follow a controllable character with a chase camera while handling input and physics for a basic third-person movement rig.","permalink":"/tutorials/third-person-controller"},{"id":"tutorials/tic-tac-toe","title":"Tic Tac Toe","description":"Implement a playable 3D tic-tac-toe board with turn handling, win detection, and UI feedback in a small sample game.","permalink":"/tutorials/tic-tac-toe"},{"id":"tutorials/timers","title":"Timers","description":"Extend the engine with one-shot timers that fire callbacks after delays while respecting global pause via time scale.","permalink":"/tutorials/timers"},{"id":"tutorials/tutorial-layout-groups","title":"Tutorial: Layout Groups","description":"Arrange buttons and panels with Layout Group and child layout rules to build responsive PlayCanvas UI flows.","permalink":"/tutorials/tutorial-layout-groups"},{"id":"tutorials/tutorial-normal-mapped-text","title":"Tutorial: Normal Mapped Text","description":"Generate normal and parallax maps for dynamic text so lettering catches light and reads embossed on surfaces.","permalink":"/tutorials/tutorial-normal-mapped-text"},{"id":"tutorials/tutorial-plasma-shader-chunk","title":"Tutorial: Plasma Shader Chunk","description":"Port a Shadertoy-style plasma effect into a material shader chunk so animated GLSL drives surface color in engine lighting.","permalink":"/tutorials/tutorial-plasma-shader-chunk"},{"id":"tutorials/tutorial-shop-user-interface","title":"Tutorial: Shop User Interface","description":"Compose a shop screen with layout groups, buttons, sprites, and atlases to list items and purchase affordances cleanly.","permalink":"/tutorials/tutorial-shop-user-interface"},{"id":"tutorials/using-events-with-scripts","title":"Using events with scripts","description":"Decouple scripts by firing and listening for custom events on entities or the application for modular gameplay messaging.","permalink":"/tutorials/using-events-with-scripts"},{"id":"tutorials/vehicle-physics","title":"Vehicle Physics","description":"Drive a wheeled vehicle with Ammo raycast wheels, suspension, and steering that works on desktop, mobile, and WebXR.","permalink":"/tutorials/vehicle-physics"},{"id":"tutorials/vhscrt-post-effect","title":"VHS/CRT Post Effect","description":"Stack scanlines, roll, and color bleed in a fullscreen pass to mimic noisy VHS and curved CRT monitor presentation.","permalink":"/tutorials/vhscrt-post-effect"},{"id":"tutorials/vignette-aberration","title":"Vignette Aberration","description":"Darken image edges with a vignette while splitting color channels for subtle chromatic aberration in a post-process pass.","permalink":"/tutorials/vignette-aberration"},{"id":"tutorials/warp-a-sprite-with-glsl","title":"Warp a Sprite with GLSL","description":"Distort sprite UVs in a custom GLSL shader to create wavy or bulging effects without rebuilding mesh geometry each frame.","permalink":"/tutorials/warp-a-sprite-with-glsl"},{"id":"tutorials/webxr-360-image","title":"WebXR 360 Image","description":"View an equirectangular 360 photo inside VR with WebXR so users can look around an immersive spherical backdrop.","permalink":"/tutorials/webxr-360-image"},{"id":"tutorials/webxr-360-video","title":"WebXR 360 Video","description":"Play omnidirectional video in a WebXR session so headset users can rotate freely while the clip streams around them.","permalink":"/tutorials/webxr-360-video"},{"id":"tutorials/webxr-ar-raycasting-shapes","title":"WebXR AR Raycasting Shapes","description":"Raycast against PlayCanvas meshes during an AR session so taps on virtual shapes work alongside the passthrough camera view.","permalink":"/tutorials/webxr-ar-raycasting-shapes"},{"id":"tutorials/webxr-ar-dom-overlay","title":"WebXR AR: DOM Overlay","description":"Combine WebXR AR with the DOM overlay API to place styled HTML/CSS UI above the camera feed without custom WebGL text.","permalink":"/tutorials/webxr-ar-dom-overlay"},{"id":"tutorials/webxr-ar-hit-test","title":"WebXR AR: Hit Test","description":"Cast rays into real-world geometry with the WebXR hit-test API to anchor virtual objects on detected floors and tables.","permalink":"/tutorials/webxr-ar-hit-test"},{"id":"tutorials/webxr-controllerhand-models","title":"WebXR Controller/Hand Models","description":"Load WebXR input profile meshes for controllers and hands so tracked hardware matches each vendor silhouette in VR.","permalink":"/tutorials/webxr-controllerhand-models"},{"id":"tutorials/webxr-hands","title":"WebXR Hands","description":"Read WebXR hand-tracking joint poses and mirror finger motion in the scene for natural direct manipulation without controllers.","permalink":"/tutorials/webxr-hands"},{"id":"tutorials/webxr-hello-world","title":"WebXR Hello World","description":"Enter immersive VR from a minimal scene with a WebXR-ready camera rig and session lifecycle hooks you can extend.","permalink":"/tutorials/webxr-hello-world"},{"id":"tutorials/webxr-realistic-hands","title":"WebXR Realistic Hands","description":"Skin tracked hand joints with detailed meshes and materials so articulated fingers read clearly in immersive VR sessions.","permalink":"/tutorials/webxr-realistic-hands"},{"id":"tutorials/webxr-tracked-controllers","title":"WebXR Tracked Controllers","description":"Follow six-DoF controllers in VR with starter code for poses, buttons, and haptics inside a PlayCanvas WebXR template.","permalink":"/tutorials/webxr-tracked-controllers"},{"id":"tutorials/webxr-vr-lab","title":"WebXR VR Lab","description":"Explore a maintained VR sandbox that demonstrates scalable interaction patterns and responsive layouts across XR devices.","permalink":"/tutorials/webxr-vr-lab"},{"id":"tutorials/webxr-ar-image-tracking","title":"WebXR: AR Image Tracking","description":"Track printed reference images in AR and align 3D content to their pose using the WebXR image-tracking extension.","permalink":"/tutorials/webxr-ar-image-tracking"},{"id":"tutorials/webxr-plane-detection","title":"WebXR: Plane Detection","description":"Subscribe to WebXR plane detection updates to visualize floor and table estimates for anchoring content to real surfaces.","permalink":"/tutorials/webxr-plane-detection"},{"id":"tutorials/world-space-ui-rendering-on-top","title":"World space UI rendering on top","description":"Layer world-space Element panels so UI quads draw after opaque geometry and stay readable over busy 3D scenes.","permalink":"/tutorials/world-space-ui-rendering-on-top"},{"id":"tutorials/world-to-ui-screen-space","title":"World to UI Screen space","description":"Project 3D world positions into screen-space anchors so labels and markers track moving objects on the 2D overlay.","permalink":"/tutorials/world-to-ui-screen-space"}],"unlisted":false}}')}}]);